import type { Product } from "@/lib/db";
import { getAllProducts, triggerCatalogSync } from "@/lib/db";
import { SyncForm } from "./sync-form";

/* ------------------------------------------------------------------ */
/*  Cached data access                                                 */
/*  Reuses "products" tag so sync actions can invalidate catalog-wide. */
/* ------------------------------------------------------------------ */

const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ["admin-catalog-products"],
  { tags: ["products"] },
);

function formatCurrency(amount: number): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
  }).format(amount);
}

function statusBadge(status: Product["status"]): string {
  const labels: Record<Product["status"], string> = {
    active: "Active",
    out_of_stock: "Out of stock",
    discontinued: "Discontinued",
  };
  return labels[status];
}

/* ------------------------------------------------------------------ */
/*  Page                                                               */
/* ------------------------------------------------------------------ */

export default async function AdminCatalogPage() {
  const products = await getCachedProducts();

  /* -------------------------------------------------------------- */
  /*  Inline Server Action — defined in the same file as the page.   */
  /*  Using "use server" directive per Next.js convention.           */
  /* -------------------------------------------------------------- */

  async function syncCatalog(formData: FormData): Promise<{
    success: boolean;
    message: string;
  }> {
    "use server";

    // 1. Invalidate the product cache so the next read re-fetches from the DB.
    revalidateTag("products");

    // 2. Kick off the upstream sync job (non-blocking from the caller's
    //    perspective; the cache is already invalidated above).
    await triggerCatalogSync();

    return {
      success: true,
      message:
        "Sync initiated — catalog data will be up to date across all views shortly.",
    };
  }

  return (
    <div className="catalog-page">
      <header className="catalog-header">
        <div>
          <h1>Product Catalog</h1>
          <p className="catalog-subtitle">
            {products.length} products &middot; Last fetched from cache
          </p>
        </div>
        <SyncForm syncAction={syncCatalog} />
      </header>

      <table className="product-table">
        <thead>
          <tr>
            <th>SKU</th>
            <th>Name</th>
            <th>Category</th>
            <th>Price</th>
            <th>Inventory</th>
            <th>Status</th>
            <th>Last Updated</th>
          </tr>
        </thead>
        <tbody>
          {products.length === 0 ? (
            <tr>
              <td colSpan={7} className="empty-state">
                No products found.
              </td>
            </tr>
          ) : (
            products.map((product) => (
              <tr key={product.id}>
                <td className="cell-sku">{product.sku}</td>
                <td className="cell-name">{product.name}</td>
                <td>{product.category}</td>
                <td className="cell-price">{formatCurrency(product.price)}</td>
                <td className="cell-inventory">
                  <span
                    className={
                      product.inventory === 0
                        ? "inventory-none"
                        : product.inventory < 50
                          ? "inventory-low"
